504 /// Wrapper to account for known fast math flags at the use instruction.
505 inline KnownFPClass computeKnownFPClass(const Value *V, FastMathFlags FMF,
506                                         FPClassTest InterestedClasses,
507                                         unsigned Depth,
508                                         const SimplifyQuery &SQ) {
509   if (FMF.noNaNs())
510     InterestedClasses &= ~fcNan;
511   if (FMF.noInfs())
512     InterestedClasses &= ~fcInf;
513 
514   KnownFPClass Result = computeKnownFPClass(V, InterestedClasses, Depth, SQ);
515 
516   if (FMF.noNaNs())
517     Result.KnownFPClasses &= ~fcNan;
518   if (FMF.noInfs())
519     Result.KnownFPClasses &= ~fcInf;
520   return Result;
521 }
