625 /// Represents offset+length into a ConstantDataArray.
626 struct ConstantDataArraySlice {
627   /// ConstantDataArray pointer. nullptr indicates a zeroinitializer (a valid
628   /// initializer, it just doesn't fit the ConstantDataArray interface).
629   const ConstantDataArray *Array;
630 
631   /// Slice starts at this Offset.
632   uint64_t Offset;
633 
634   /// Length of the slice.
635   uint64_t Length;
636 
637   /// Moves the Offset and adjusts Length accordingly.
638   void move(uint64_t Delta) {
639     assert(Delta < Length);
640     Offset += Delta;
641     Length -= Delta;
642   }
643 
644   /// Convenience accessor for elements in the slice.
645   uint64_t operator[](unsigned I) const {
646     return Array == nullptr ? 0 : Array->getElementAsInteger(I + Offset);
