702 /// This method is similar to getUnderlyingObject except that it can
703 /// look through phi and select instructions and return multiple objects.
704 ///
705 /// If LoopInfo is passed, loop phis are further analyzed.  If a pointer
706 /// accesses different objects in each iteration, we don't look through the
707 /// phi node. E.g. consider this loop nest:
708 ///
709 ///   int **A;
710 ///   for (i)
711 ///     for (j) {
712 ///        A[i][j] = A[i-1][j] * B[j]
713 ///     }
714 ///
715 /// This is transformed by Load-PRE to stash away A[i] for the next iteration
716 /// of the outer loop:
717 ///
718 ///   Curr = A[0];          // Prev_0
719 ///   for (i: 1..N) {
720 ///     Prev = Curr;        // Prev = PHI (Prev_0, Curr)
721 ///     Curr = A[i];
722 ///     for (j: 0..N) {
723 ///        Curr[j] = Prev[j] * B[j]
724 ///     }
725 ///   }
726 ///
727 /// Since A[i] and A[i-1] are independent pointers, getUnderlyingObjects
728 /// should not assume that Curr and Prev share the same underlying object thus
729 /// it shouldn't look through the phi above.
